// --- utils/encryption.ts ---
import CryptoJS from 'crypto-js';

const ENCRYPTION_KEY_PREFIX = 'PM_ENC_';

export class EncryptionService {
  private key: string;

  constructor(userKey: string) {
    this.key = `${ENCRYPTION_KEY_PREFIX}${userKey}`;
  }

  encrypt(data: string): string {
    try {
      const encrypted = CryptoJS.AES.encrypt(data, this.key).toString();
      return encrypted;
    } catch (error) {
      throw new Error('Encryption failed');
    }
  }

  decrypt(encryptedData: string): string {
    try {
      const bytes = CryptoJS.AES.decrypt(encryptedData, this.key);
      const decrypted = bytes.toString(CryptoJS.enc.Utf8);
      if (!decrypted) {
        throw new Error('Decryption produced empty result');
      }
      return decrypted;
    } catch (error) {
      throw new Error('Decryption failed');
    }
  }

  hashSensitiveData(data: string): string {
    return CryptoJS.SHA256(data).toString();
  }

  generateNonce(): string {
    return CryptoJS.lib.WordArray.random(16).toString();
  }
}

// --- utils/secureStorage.ts ---
import * as Keychain from 'react-native-keychain';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { EncryptionService } from './encryption';

const SECURE_PREFIX = '@payment_secure_';

export class SecureStorage {
  private encryption: EncryptionService;

  constructor(encryption: EncryptionService) {
    this.encryption = encryption;
  }

  async storeSecure(key: string, value: string): Promise<void> {
    try {
      // Use Keychain for most sensitive data
      await Keychain.setGenericPassword(
        `${SECURE_PREFIX}${key}`,
        this.encryption.encrypt(value),
        {
          service: `${SECURE_PREFIX}${key}`,
          accessControl: Keychain.ACCESS_CONTROL.BIOMETRY_CURRENT_SET_OR_DEVICE_PASSCODE,
          accessible: Keychain.ACCESSIBLE.WHEN_UNLOCKED_THIS_DEVICE_ONLY,
        }
      );
    } catch (error) {
      // Fallback to encrypted AsyncStorage
      const encrypted = this.encryption.encrypt(value);
      await AsyncStorage.setItem(`${SECURE_PREFIX}${key}`, encrypted);
    }
  }

  async retrieveSecure(key: string): Promise<string | null> {
    try {
      const credentials = await Keychain.getGenericPassword({
        service: `${SECURE_PREFIX}${key}`,
      });
      if (credentials) {
        return this.encryption.decrypt(credentials.password);
      }
      return null;
    } catch (error) {
      // Fallback to encrypted AsyncStorage
      const encrypted = await AsyncStorage.getItem(`${SECURE_PREFIX}${key}`);
      if (encrypted) {
        return this.encryption.decrypt(encrypted);
      }
      return null;
    }
  }

  async removeSecure(key: string): Promise<void> {
    try {
      await Keychain.resetGenericPassword({
        service: `${SECURE_PREFIX}${key}`,
      });
    } catch {
      // ignore
    }
    await AsyncStorage.removeItem(`${SECURE_PREFIX}${key}`);
  }

  async clearAll(): Promise<void> {
    const keys = await AsyncStorage.getAllKeys();
    const paymentKeys = keys.filter((k) => k.startsWith(SECURE_PREFIX));
    await AsyncStorage.multiRemove(paymentKeys);
  }
}

// --- utils/validation.ts ---
export class PaymentValidator {
  static validateAmount(amount: number, currency: string): boolean {
    if (amount <= 0) return false;
    if (!Number.isFinite(amount)) return false;

    // Currency-specific validation
    const minAmounts: Record<string, number> = {
      USD: 0.5,
      EUR: 0.5,
      GBP: 0.3,
      JPY: 50,
    };

    const min = minAmounts[currency] || 0.01;
    return amount >= min;
  }

  static validateCurrency(currency: string): boolean {
    const validCurrencies = ['USD', 'EUR', 'GBP', 'JPY', 'CAD', 'AUD', 'CHF', 'CNY', 'INR'];
    return validCurrencies.includes(currency.toUpperCase());
  }

  static sanitizeInput(input: string): string {
    return input.replace(/[<>\"\'&]/g, '').trim();
  }

  static validateProductId(productId: string): boolean {
    return /^[a-zA-Z0-9._-]+$/.test(productId) && productId.length <= 150;
  }

  static validateCardNumber(cardNumber: string): boolean {
    // Luhn algorithm
    const sanitized = cardNumber.replace(/\s/g, '');
    if (!/^\d{13,19}$/.test(sanitized)) return false;

    let sum = 0;
    let isEven = false;

    for (let i = sanitized.length - 1; i >= 0; i--) {
      let digit = parseInt(sanitized[i], 10);
      if (isEven) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }
      sum += digit;
      isEven = !isEven;
    }

    return sum % 10 === 0;
  }

  static validateExpiry(month: number, year: number): boolean {
    const now = new Date();
    const currentMonth = now.getMonth() + 1;
    const currentYear = now.getFullYear();

    if (month < 1 || month > 12) return false;
    if (year < currentYear) return false;
    if (year === currentYear && month < currentMonth) return false;

    return true;
  }

  static validateCVV(cvv: string): boolean {
    return /^\d{3,4}$/.test(cvv);
  }
}

// --- services/rateLimiter.ts ---
export class RateLimiter {
  private attempts: Map<string, number[]> = new Map();
  private maxAttempts: number;
  private windowMs: number;

  constructor(maxAttempts: number = 5, windowMs: number = 60000) {
    this.maxAttempts = maxAttempts;
    this.windowMs = windowMs;
  }

  canProceed(key: string): boolean {
    const now = Date.now();
    const attempts = this.attempts.get(key) || [];

    // Remove expired attempts
    const validAttempts = attempts.filter((t) => now - t < this.windowMs);
    this.attempts.set(key, validAttempts);

    return validAttempts.length < this.maxAttempts;
  }

  recordAttempt(key: string): void {
    const attempts = this.attempts.get(key) || [];
    attempts.push(Date.now());
    this.attempts.set(key, attempts);
  }

  getRemainingAttempts(key: string): number {
    const now = Date.now();
    const attempts = (this.attempts.get(key) || []).filter(
      (t) => now - t < this.windowMs
    );
    return Math.max(0, this.maxAttempts - attempts.length);
  }

  getResetTime(key: string): number {
    const attempts = this.attempts.get(key) || [];
    if (attempts.length === 0) return 0;
    const oldest = Math.min(...attempts);
    return Math.max(0, this.windowMs - (Date.now() - oldest));
  }

  reset(key: string): void {
    this.attempts.delete(key);
  }
}

// --- services/fraudDetection.ts ---
import { Transaction, PaymentError } from '../types/payment';

interface FraudSignal {
  type: string;
  severity: 'low' | 'medium' | 'high';
  description: string;
}

export class FraudDetectionService {
  private recentTransactions: Transaction[] = [];
  private readonly MAX_TRANSACTION_VELOCITY = 10; // per hour
  private readonly MAX_AMOUNT_PER_HOUR = 5000;
  private readonly SUSPICIOUS_AMOUNT_THRESHOLD = 1000;

  analyzeTransaction(
    transaction: Partial<Transaction>,
    deviceInfo: Record<string, any>
  ): { approved: boolean; signals: FraudSignal[]; riskScore: number } {
    const signals: FraudSignal[] = [];
    let riskScore = 0;

    // Velocity check
    const recentCount = this.getRecentTransactionCount(60);
    if (recentCount >= this.MAX_TRANSACTION_VELOCITY) {
      signals.push({
        type: 'velocity',
        severity: 'high',
        description: 'Transaction velocity exceeded threshold',
      });
      riskScore += 40;
    } else if (recentCount >= this.MAX_TRANSACTION_VELOCITY * 0.7) {
      signals.push({
        type: 'velocity',
        severity: 'medium',
        description: 'Transaction velocity approaching threshold',
      });
      riskScore += 20;
    }

    // Amount check
    const hourlyTotal = this.getHourlyTotal();
    if (
      hourlyTotal + (transaction.amount || 0) >
      this.MAX_AMOUNT_PER_HOUR
    ) {
      signals.push({
        type: 'amount_limit',
        severity: 'high',
        description: 'Hourly amount limit exceeded',
      });
      riskScore += 35;
    }

    // Suspicious amount
    if ((transaction.amount || 0) >= this.SUSPICIOUS_AMOUNT_THRESHOLD) {
      signals.push({
        type: 'high_amount',
        severity: 'medium',
        description: 'Transaction amount is unusually high',
      });
      riskScore += 15;
    }

    // Rapid successive transactions
    const lastTransaction = this.recentTransactions[this.recentTransactions.length - 1];
    if (lastTransaction) {
      const timeDiff = Date.now() - lastTransaction.timestamp;
      if (timeDiff < 5000) {
        signals.push({
          type: 'rapid_succession',
          severity: 'medium',
          description: 'Transaction attempted too quickly after previous',
        });
        riskScore += 25;
      }
    }

    // Device anomaly check
    if (deviceInfo.isEmulator) {
      signals.push({
        type: 'emulator',
        severity: 'high',
        description: 'Transaction from emulator detected',
      });
      riskScore += 50;
    }

    if (deviceInfo.isRooted || deviceInfo.isJailbroken) {
      signals.push({
        type: 'compromised_device',
        severity: 'high',
        description: 'Transaction from compromised device',
      });
      riskScore += 30;
    }

    return {
      approved: riskScore < 50,
      signals,
      riskScore: Math.min(100, riskScore),
    };
  }

  recordTransaction(transaction: Transaction): void {
    this.recentTransactions.push(transaction);
    // Keep only last 24 hours
    const cutoff = Date.now() - 24 * 60 * 60 * 1000;
    this.recentTransactions = this.recentTransactions.filter(
      (t) => t.timestamp > cutoff
    );
  }

  private getRecentTransactionCount(minutes: number): number {
    const cutoff = Date.now() - minutes * 60 * 1000;
    return this.recentTransactions.filter((t) => t.timestamp > cutoff).length;
  }

  private getHourlyTotal(): number {
    const cutoff = Date.now() - 60 * 60 * 1000;
    return this.recentTransactions
      .filter((t) => t.timestamp > cutoff)
      .reduce((sum, t) => sum + t.amount, 0);
  }
}

